import { useState, useRef } from "react";
import { Volume2, RotateCcw, Check } from "lucide-react";

const INK = "#211A2C";
const SURFACE = "#2F2640";
const SURFACE_LIGHT = "#3D314F";
const CREAM = "#F3E9D2";
const CREAM_DIM = "#B7A9C9";
const MARIGOLD = "#E8932E";
const PEACOCK = "#2F8F84";
const KUMKUM = "#D1432B";

const REFERENCE_IMAGE = "data:image/png;base64,";

// Stroke order for अ: 5 strokes, each a centerline path. Badges sit at
// whichever end of the stroke the original diagram labels (start for
// stroke 2, end for the rest). Add more letters here the same way.
const LETTER = {
  char: "अ",
  roman: "a",
  viewBox: "0 0 300 343",
  strokes: [
    { label: "Upper curve", d: "M118,8 C45,5 10,45 10,100 C10,135 35,155 80,145", badge: { x: 80, y: 145 } },
    { label: "Lower curve", d: "M20,190 C5,235 10,290 55,310 C100,328 148,295 150,250 C151,222 142,206 135,200", badge: { x: 20, y: 190 } },
    { label: "Connecting bar", d: "M138,172 L228,172", badge: { x: 228, y: 172 } },
    { label: "Vertical stem", d: "M234,25 L234,325", badge: { x: 234, y: 325 } },
    { label: "Top bar", d: "M176,25 L278,25", badge: { x: 278, y: 25 } },
  ],
};

function speak(text) {
  try {
    window.speechSynthesis.cancel();
    const utter = new SpeechSynthesisUtterance(text);
    utter.lang = "hi-IN";
    utter.rate = 0.8;
    window.speechSynthesis.speak(utter);
  } catch (e) {
    /* speech synthesis unavailable in this environment */
  }
}

function pointsToPath(points) {
  if (points.length === 0) return "";
  return "M" + points.map((p) => `${p.x},${p.y}`).join(" L ");
}

export default function StrokeOrderTracing() {
  const [strokeIndex, setStrokeIndex] = useState(0);
  const [points, setPoints] = useState([]);
  const [hasDrawn, setHasDrawn] = useState(false);
  const [finished, setFinished] = useState(false);
  const svgRef = useRef(null);
  const isDrawing = useRef(false);

  const total = LETTER.strokes.length;
  const current = LETTER.strokes[strokeIndex];
  const completed = LETTER.strokes.slice(0, strokeIndex);

  function getSvgPoint(e) {
    const svg = svgRef.current;
    const pt = svg.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    const ctm = svg.getScreenCTM();
    if (!ctm) return { x: 0, y: 0 };
    const transformed = pt.matrixTransform(ctm.inverse());
    return { x: transformed.x, y: transformed.y };
  }

  function handleDown(e) {
    isDrawing.current = true;
    setPoints([getSvgPoint(e)]);
    setHasDrawn(true);
  }
  function handleMove(e) {
    if (!isDrawing.current) return;
    setPoints((pts) => [...pts, getSvgPoint(e)]);
  }
  function handleUp() {
    isDrawing.current = false;
  }
  function clearStroke() {
    setPoints([]);
    setHasDrawn(false);
  }
  function nextStroke() {
    if (strokeIndex + 1 < total) {
      setStrokeIndex((i) => i + 1);
      setPoints([]);
      setHasDrawn(false);
    } else {
      setFinished(true);
    }
  }
  function restart() {
    setStrokeIndex(0);
    setPoints([]);
    setHasDrawn(false);
    setFinished(false);
  }

  const userPath = pointsToPath(points);

  return (
    <div className="so-root min-h-screen">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Baloo+2:wght@500;600;700;800&family=Poppins:wght@400;500;600;700&family=JetBrains+Mono:wght@500;700&display=swap');
        .so-root { background: ${INK}; color: ${CREAM}; font-family: 'Poppins', sans-serif; }
        .so-display { font-family: 'Baloo 2', sans-serif; }
        .so-mono { font-family: 'JetBrains Mono', monospace; }
        .so-wrap { max-width: 960px; margin: 0 auto; padding: 32px 20px 48px; }
        .so-layout { display: flex; gap: 28px; align-items: flex-start; }
        .so-left { flex: 0 0 360px; }
        .so-right { flex: 1; min-width: 280px; }
        @media (max-width: 760px) {
          .so-layout { flex-direction: column; }
          .so-left { flex: 1; width: 100%; }
        }
        button:focus-visible { outline: 2px solid ${MARIGOLD}; outline-offset: 2px; }
      `}</style>

      <div className="so-wrap">
        <h1 className="so-display text-2xl font-bold mb-1">अ — Stroke Order Tracing</h1>
        <p className="text-sm mb-6" style={{ color: CREAM_DIM }}>
          Reference on the left, live practice on the right. Follow the same 5 strokes, in order.
        </p>

        <div className="so-layout">
          <div className="so-left">
            <div className="rounded-3xl overflow-hidden mb-4" style={{ border: `3px solid ${SURFACE_LIGHT}` }}>
              <img src={REFERENCE_IMAGE} alt="Stroke order reference for अ" className="w-full block" />
            </div>
            <div className="rounded-2xl p-4" style={{ background: SURFACE }}>
              {LETTER.strokes.map((s, i) => (
                <div
                  key={i}
                  className="flex items-center gap-3 py-1.5"
                  style={{ opacity: i === strokeIndex && !finished ? 1 : 0.5 }}
                >
                  <span
                    className="so-mono flex items-center justify-center rounded-full font-bold text-xs flex-shrink-0"
                    style={{
                      width: 22,
                      height: 22,
                      background: i < strokeIndex || finished ? PEACOCK : i === strokeIndex ? MARIGOLD : SURFACE_LIGHT,
                      color: INK,
                    }}
                  >
                    {i + 1}
                  </span>
                  <span className="text-sm font-medium">{s.label}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="so-right">
            {!finished ? (
              <>
                <div className="flex items-center gap-3 mb-4">
                  <div className="flex-1 rounded-full overflow-hidden" style={{ height: 8, background: SURFACE_LIGHT }}>
                    <div
                      className="h-full rounded-full"
                      style={{ width: `${((strokeIndex + (hasDrawn ? 0.5 : 0)) / total) * 100}%`, background: MARIGOLD, transition: "width 0.2s" }}
                    />
                  </div>
                  <span className="so-mono text-sm font-bold">{strokeIndex + 1}/{total}</span>
                </div>

                <div className="flex items-center gap-3 mb-4">
                  <button
                    onClick={() => speak(LETTER.char)}
                    className="flex items-center justify-center rounded-full flex-shrink-0"
                    style={{ width: 40, height: 40, background: SURFACE_LIGHT }}
                  >
                    <Volume2 size={18} color={MARIGOLD} />
                  </button>
                  <span className="text-base font-semibold">Trace: {current.label}</span>
                </div>

                <svg
                  ref={svgRef}
                  viewBox={LETTER.viewBox}
                  onPointerDown={handleDown}
                  onPointerMove={handleMove}
                  onPointerUp={handleUp}
                  onPointerLeave={handleUp}
                  style={{
                    width: "100%",
                    maxWidth: 320,
                    aspectRatio: "300/343",
                    background: SURFACE_LIGHT,
                    borderRadius: 24,
                    border: `3px dashed rgba(243,233,210,0.25)`,
                    touchAction: "none",
                    cursor: "crosshair",
                    display: "block",
                  }}
                  className="mb-6"
                >
                  <defs>
                    <marker id="arrowhead" markerWidth="9" markerHeight="9" refX="6" refY="3" orient="auto" markerUnits="strokeWidth">
                      <path d="M0,0 L7,3 L0,6 Z" fill={CREAM} />
                    </marker>
                  </defs>

                  {completed.map((s, i) => (
                    <path key={i} d={s.d} stroke={KUMKUM} strokeWidth="30" fill="none" strokeLinecap="round" strokeLinejoin="round" />
                  ))}

                  <path d={current.d} stroke={CREAM} strokeWidth="4" strokeDasharray="9 8" fill="none" markerEnd="url(#arrowhead)" opacity="0.85" />
                  <circle cx={current.badge.x} cy={current.badge.y} r="15" fill={CREAM} stroke={INK} strokeWidth="2" />
                  <text x={current.badge.x} y={current.badge.y + 1} textAnchor="middle" dominantBaseline="middle" fontSize="15" fontWeight="700" fill={INK}>
                    {strokeIndex + 1}
                  </text>

                  {userPath && <path d={userPath} stroke={MARIGOLD} strokeWidth="12" fill="none" strokeLinecap="round" strokeLinejoin="round" />}
                </svg>

                <div className="flex gap-3 w-full" style={{ maxWidth: 320 }}>
                  <button
                    onClick={clearStroke}
                    className="flex-1 flex items-center justify-center gap-2 rounded-full py-3 font-semibold"
                    style={{ background: SURFACE_LIGHT, color: CREAM }}
                  >
                    <RotateCcw size={16} /> Clear
                  </button>
                  <button
                    onClick={nextStroke}
                    disabled={!hasDrawn}
                    className="flex-1 rounded-full py-3 font-bold"
                    style={{ background: hasDrawn ? PEACOCK : SURFACE_LIGHT, color: hasDrawn ? INK : CREAM_DIM }}
                  >
                    {strokeIndex + 1 < total ? "Next stroke" : "Finish"}
                  </button>
                </div>
              </>
            ) : (
              <div className="rounded-3xl p-8 flex flex-col items-center text-center" style={{ background: SURFACE, maxWidth: 320 }}>
                <div className="flex items-center justify-center rounded-full mb-5" style={{ width: 88, height: 88, border: `4px dashed ${PEACOCK}` }}>
                  <Check size={36} color={PEACOCK} />
                </div>
                <h2 className="so-display text-xl font-bold mb-1">सब पाँच हो गए!</h2>
                <p className="text-sm mb-6" style={{ color: CREAM_DIM }}>All 5 strokes of अ, in order.</p>
                <button
                  onClick={restart}
                  className="w-full rounded-full py-3 font-bold"
                  style={{ background: MARIGOLD, color: INK }}
                >
                  Practice again
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
